module top_module(
    input [2:0] D,
    output reg [3:0] obf_BCD
);always @(*) begin
    case(D)
        3'b000: obf_BCD = 4'b0000;
        3'b001: obf_BCD = 4'b0001;
        3'b010: obf_BCD = 4'b0010;
        3'b011: obf_BCD = 4'b0011;
        3'b100: obf_BCD = 4'b0100;
        3'b101: obf_BCD = 4'b0101;
        3'b110: obf_BCD = 4'b0110;
        3'b111: obf_BCD = 4'b0111;
    endcase
end

endmodule
